module comparator (
    input [3:0] obf_a,
    input [3:0] b,
    output reg lt,
    output reg eq,
    output reg gt
);

    always @(*) begin
        if (obf_a < b) begin
            lt = 1;
            eq = 0;
            gt = 0;
        end else if (obf_a == b) begin
            lt = 0;
            eq = 1;
            gt = 0;
        end else begin
            lt = 0;
            eq = 0;
            gt = 1;
        end
    end
endmodule
